// Arithmetic
let sum: number = 10 + 5;
let power: number = 2 ** 8;

// Comparison - always use strict
let isEqual: boolean = 5 === "5"; // false
let isLoose: boolean = 5 == "5"; // true (avoid)

// Nullish coalescing
let input: string | null = null;
let output: string = input ?? "fallback";

// Optional chaining
let user: { address?: { city?: string } } = {};
let city: string | undefined = user?.address?.city;
